@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.RenderModeAttribute(typeof(NoInteractiveRenderMode))]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<p>
    This page describes how the application collects, uses, and shares your
    personal data. By using this site you agree to our use of cookies as
    described below.
</p>

<h2>Cookies We Use</h2>
<ul>
    <li><strong>Essential cookies</strong> – required for the site to function.</li>
    <li><strong>Analytics cookies</strong> – help us understand how visitors interact with the site.</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw your consent at any time by clearing your browser cookies.
</p>

@code {
    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            HasConsented = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

// Marker type used with @attribute [RenderModeAttribute(...)] to signal that
// a page should NOT be rendered interactively.  App.razor checks for this
// attribute when deciding whether to apply the global InteractiveServer mode.

namespace Microsoft.AspNetCore.Components;

/// <summary>
/// A sentinel <see cref="IComponentRenderMode"/> that tells the router to
/// skip the global interactive render mode and keep the page in static SSR.
/// </summary>
public sealed class NoInteractiveRenderMode : IComponentRenderMode { }

