@code {
    /// <summary>
    /// Returns <c>null</c> (static SSR) when the routed page carries a
    /// <see cref="RenderModeAttribute"/> pointing to
    /// <see cref="NoInteractiveRenderMode"/>; otherwise returns
    /// <see cref="RenderMode.InteractiveServer"/> so the rest of the app
    /// keeps its global interactivity.
    /// </summary>
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode => PageRequestsStaticRendering()
        ? null
        : RenderMode.InteractiveServer;

    private bool PageRequestsStaticRendering()
    {
        var endpoint = HttpContext?.GetEndpoint();
        if (endpoint is null)
            return false;

        var renderModeAttr = endpoint.Metadata
            .GetMetadata<RenderModeAttribute>();

        return renderModeAttr?.Mode is NoInteractiveRenderMode;
    }
}
"}

